  // { json: { source: "Towards Data Science", feed: "https://towardsdatascience.com/feed" } },
];

// 🧹 Normalize + Canonicalize + Deduplicate (batch) + Filter Out Weak Summaries
// Outputs: uid (normalized full URL), url_norm (same), canon_key (host/path?query)

const stripHtml = (s) => (s ? String(s).replace(/<[^>]+>/g, ' ') : '');
const squeeze = (s) => s.replace(/\s+/g, ' ').trim();
const stripBoilerplate = (s) =>
  s.replace(/\bThe (article|post)\b.*?\bappeared first on\b.*$/i, '').trim();

// Build a normalized FULL URL (https://host/path?query) and a protocol-less key
function normalizeUrl(raw) {
  if (!raw) return { url_norm: '', canon_key: '' };
  try {
    const u = new URL(raw);
    // prefer https
    u.protocol = 'https:';
    // strip www.
    u.hostname = u.hostname.replace(/^www\./i, '').toLowerCase();
    // trim path
    let path = u.pathname.replace(/\/+$/, '');
    path = path.replace(/\/index\.(html|htm|php)$/i, '');
    path = path.replace(/\/amp$/i, '');
    u.pathname = path || '/';

    // remove tracking params
    const keep = [];
    u.searchParams.forEach((v, k) => {
      if (!/^utm_/i.test(k) && !/^(ref|fbclid|gclid|igshid|mc_cid|mc_eid)$/i.test(k)) {
        keep.push([k, v]);
      }
    });
    u.search = '';
    keep.forEach(([k, v]) => u.searchParams.append(k, v));

    u.hash = '';

    const url_norm = u.toString(); // full https URL
    const canon_key = `${u.hostname}${u.pathname}${u.search}`; // no protocol
    return { url_norm, canon_key };
  } catch {
    // fallback: clean obvious double https
    const cleaned = String(raw).replace(/^https?:\/\/https?:\/\//i, 'https://').trim();
    // try to at least strip www. for key
    const match = cleaned.match(/^https?:\/\/([^/]+)(\/[^?#]*)?(\?[^#]*)?/i);
    const host = match ? match[1].replace(/^www\./i, '').toLowerCase() : '';
    const path = (match && match[2]) ? match[2].replace(/\/+$/, '') || '/' : '/';
    const search = (match && match[3]) ? match[3] : '';
    return { url_norm: cleaned, canon_key: `${host}${path}${search}` };
  }
}

const toISO = (val) => {
  const d = new Date(val);
  return isNaN(d) ? '' : d.toISOString();
};

const clampText = (s, { min = 50, max = 400 } = {}) => {
  const t = s.length > max ? s.slice(0, max + 1) : s;
  let out = t;
  if (t.length > max) {
    const cut = t.lastIndexOf(' ');
    out = (cut > min ? t.slice(0, cut) : t.slice(0, max)).trim() + '…';
  }
  return out;
};

// ---- main ----
const seen = new Set(); // dedupe within this batch by canon_key
const out = [];

for (const item of $input.all()) {
  const j = item.json || {};

  const rawTitle = j.title || '';
  const title = squeeze(stripHtml(rawTitle));
  const rawLink = (j.canonical || j.link || '').trim();
  if (!title || !rawLink) continue;

  const { url_norm, canon_key } = normalizeUrl(rawLink);
  if (!canon_key) continue;
  if (seen.has(canon_key)) continue; // batch dedupe
  seen.add(canon_key);

  let source = 'unknown';
  try { source = new URL(url_norm).hostname.replace(/^www\./i, '').toLowerCase(); } catch {}

  const author = j.creator || j['dc:creator'] || j.author || '';
  const categories = Array.isArray(j.categories)
    ? Array.from(new Set(j.categories.map(c => String(c).trim()).filter(Boolean)))
    : [];

  const rawSummary = j.contentSnippet || j.summary || j.content || '';
  let summary = squeeze(stripBoilerplate(stripHtml(rawSummary)));
  if (!summary || summary.length < 30) continue;
  summary = clampText(summary, { min: 50, max: 400 });

  const published = toISO(j.isoDate || j.pubDate || j.published || '');

  // uid: use normalized full URL so it matches exactly in Notion later
  const uid = url_norm;

  out.push({
    json: {
      title,
      source,
      author,
      categories,
      summary,
      link: rawLink,   // original for reference
      url_norm,        // normalized full URL
      canon_key,       // protocol-less key (optional)
      uid,             // stable id for de-dupe in Notion
      published
    }
  });
}

return out;

// 🧠 Define relevant keywords (edit anytime)
const KEYWORDS = [
  // Core
  "automation", "ai automation", "workflow automation", "business automation", "process automation",
  // Virtual assistant / staffing context
  "virtual assistant", "remote work", "outsourcing", "productivity", "operations", "scaling", "efficiency",
  // Tools / ecosystems SV uses or tracks
  "n8n", "make.com", "zapier", "airtable", "notion", "slack", "supabase", "monday.com", "clickup",
  // AI tools relevant to your operations
  "chatgpt", "claude", "anthropic", "openai", "gpt", "ai tools", "agentic", "agents", "ai agents", "copilot"
];

// helper: case-insensitive match
const matchesKeyword = (text) => {
  if (!text) return false;
  const lower = String(text).toLowerCase();
  return KEYWORDS.some(k => lower.includes(k.toLowerCase()));
};

// --- SETTINGS ---
const CAP = null;          // keep top N after shuffle (set null to keep all)
const USE_DAILY_SEED = true; // true => random-but-stable per day; false => fully random

// seeded RNG (Mulberry32)
function mulberry32(seed) {
  return function () {
    let t = seed += 0x6D2B79F5;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// Fisher–Yates shuffle with injectable RNG
function shuffle(arr, rand = Math.random) {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(rand() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

// 1) filter
const filtered = $input.all().filter(item => {
  const t = item.json.title || "";
  const c = item.json.contentSnippet || item.json.content || "";
  const cats = (item.json.categories || []).join(" ").toLowerCase();
  return matchesKeyword(t) || matchesKeyword(c) || matchesKeyword(cats);
});

// 2) optional: deterministic seed per day
let rand = Math.random;
if (USE_DAILY_SEED) {
  const ymd = new Date().toISOString().slice(0,10).replace(/-/g, ""); // e.g., 20251024
  rand = mulberry32(parseInt(ymd, 10));
}

// 3) shuffle
const shuffled = shuffle(filtered, rand);

// 4) optional cap
return CAP ? shuffled.slice(0, CAP) : shuffled;

// Gmail Composer — long date, no item count, source fallback, show author
// SUBJECT DATE = RUN DATE (Asia/Manila)

const incoming = $input.all();

function esc(s='') {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function joinArray(arr, sep=' ') {
  return (Array.isArray(arr) ? arr : []).map(v => String(v||'').trim()).filter(Boolean).join(sep);
}
function hostName(u='') {
  try {
    const h = new URL(u).hostname.replace(/^www\./,'');
    const core = h.split('.')[0].replace(/-/g,' ');
    return core ? core.replace(/\b\w/g, c => c.toUpperCase()) : h;
  } catch { return ''; }
}
function fmtDate(input) {
  const d = (input instanceof Date) ? input : new Date(input);
  if (isNaN(d)) return String(input || '');
  return new Intl.DateTimeFormat('en-US', {
    month:'long', day:'numeric', year:'numeric',
    timeZone: 'Asia/Manila', // <-- set your timezone here
  }).format(d);
}

function normalizeArticle(j) {
  const title = j.notion_title || j.title || '';
  const url   = j.notion_url   || j.url   || j.uid || '';
  const uid   = j.notion_uid   || j.uid   || '';
  const published = j.notion_published || j.published || '';
  const sourceRaw = j.notion_source || j.source || '';
  const author = j.notion_author || j.author || '';
  const categories = Array.isArray(j.categories) ? j.categories : [];
  const refs = Array.isArray(j.refs) ? j.refs : [];

  // summaries/insights (prefer *_text if present)
  const summaryPara  = j.summary_text || joinArray(j.summary, ' ');
  const insightsList = Array.isArray(j.insights)
    ? j.insights
    : (j.insights_text ? j.insights_text.split('\n').map(s => s.trim()).filter(Boolean) : []);
  const tagsStr = j.tags_text || joinArray(j.tags, ', ');

  // Fallback: if source missing/unknown, derive from URL/UID
  const urlForHost = url || uid;
  const displaySource = (sourceRaw && String(sourceRaw).toLowerCase() !== 'unknown')
    ? sourceRaw
    : hostName(urlForHost);

  return { title, url, uid, published, displaySource, author, categories, refs,
           summaryPara, insightsList, tagsStr };
}

const articles = incoming
  .map(it => normalizeArticle(it.json || {}))
  .filter(a => a.title || a.summaryPara);

// Subject date = RUN DATE (not latest article date)
const subjectDate = fmtDate(new Date());
const subject = `🔎 What's New With AI? — ${subjectDate}`; // no item count

const sections = articles.map((a, i) => {
  const metaParts = [];
  const leftBits = [a.displaySource, a.author].filter(Boolean).map(esc);
  if (leftBits.length) metaParts.push(leftBits.join(' — '));
  if (a.published) metaParts.push(fmtDate(a.published));
  const meta = metaParts.join(' • ');

  return `
  <tr>
    <td style="padding:16px 0;border-top:1px solid #eee;">
      <div style="font-size:16px;font-weight:600;margin-bottom:4px;">
        ${i+1}) ${a.url ? `<a href="${a.url}" style="color:#0b57d0;text-decoration:none;">${esc(a.title)}</a>` : esc(a.title)}
      </div>
      <div style="color:#666;font-size:12px;margin-bottom:8px;">${meta}</div>
      ${a.summaryPara ? `<div style="font-size:14px;line-height:1.5;margin-bottom:8px;white-space:pre-line;">${esc(a.summaryPara)}</div>` : ''}
      ${a.insightsList.length ? `<div style="font-size:14px;margin:8px 0 4px;font-weight:600;">SV takeaways</div>
        <ul style="margin:0 0 8px 18px;padding:0;">
          ${a.insightsList.map(t=>`<li style="margin:0 0 4px 0;">${esc(t)}</li>`).join('')}
        </ul>` : ''}
      ${a.tagsStr ? `<div style="font-size:12px;color:#666;"><b>Tags:</b> ${esc(a.tagsStr)}</div>` : ''}
      ${a.refs && a.refs.length ? `<div style="font-size:12px;color:#666;margin-top:4px;"></div>` : ''}
    </td>
  </tr>`;
}).join('');

const html = `
<table width="600" cellpadding="0" cellspacing="0" style="font-family:system-ui,-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;color:#111;margin:auto;">
  <tr><td style="padding:12px 0;">
    <div style="font-size:18px;font-weight:700;">What's New With AI? — ${subjectDate}</div>
    <div style="font-size:13px;color:#666;">What matters for Scale Virtually</div>
  </td></tr>
  ${sections || `<tr><td style="padding:16px 0;border-top:1px solid #eee;">No articles.</td></tr>`}
</table>`.trim();

return [{ json: { email: { subject, html } } }];

// Run Once for All Items
// Input items contain: article_html[], title, source, author, categories[],
// link, url_norm, url, uid, published, ...

function normalizeText(s) {
  return String(s ?? "")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function extractUrls(text) {
  const out = new Set();
  const t = String(text || "");
  const rx = /https?:\/\/[^\s\]\)]+/g; // bare links or inside []/()
  let m;
  while ((m = rx.exec(t)) !== null) out.add(m[0].replace(/[),.;:]+$/, ""));
  return [...out];
}

function countWords(t) {
  return normalizeText(t).split(/\s+/).filter(Boolean).length;
}

const articles = items.map(({ json: j }) => {
  const parts = Array.isArray(j.article_html) ? j.article_html.filter(Boolean) : [];
  const full_text = normalizeText(parts.join("\n\n"));

  return {
    // Passthrough metadata — NEVER null (empty string if missing)
    uid: j.uid || j.link || j.url_norm || j.url || "",
    title: j.title || "",
    url: j.link || j.url_norm || j.url || "",
    published: j.published || "",
    source: j.source || "",
    author: j.author || "",
    categories: Array.isArray(j.categories) ? j.categories : [],
    refs: extractUrls(full_text),

    // Context for the model (not part of final schema, but helpful)
    full_text,
    word_count: countWords(full_text),
  };
});

return [
  {
    json: {
      instruction:
        "For each article, provide: (1) 3–5 sentence summary (no bullets/numbering/emojis), (2) 1–2 insights linking it to Scale Virtually’s strategy/customers/GTM (plain sentences), (3) suggested Notion tags.",
      articles,
    },
  },
];

function normTitle(s = '') {
  return String(s).trim().toLowerCase().replace(/\s+/g, ' ');
}

return items.map(it => {
  const j = it.json || {};
  const title =
    j.property_name ?? j.name ?? j.title ?? j.notion_title ?? '';
  return {
    json: {
      ...j,
      title_key: normTitle(title),
    },
  };
});

function normTitle(s = '') {
  return String(s).trim().toLowerCase().replace(/\s+/g, ' ');
}

return items.map(it => {
  const j = it.json || {};
  const title = j.title ?? j.notion_title ?? '';
  return {
    json: {
      ...j,
      title_key: normTitle(title),
    },
  };
});

// Hardened LLM Cleaner — finds JSON anywhere (Gemini or custom wrappers)
// Emits one item per article with Notion-friendly fields.

function normalizeArray(a) {
  return Array.isArray(a)
    ? a.filter(v => v !== null && v !== undefined && String(v).trim() !== "")
    : [];
}
function lcHyphenateTag(t) {
  return String(t || "")
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[^\w\s-]/g, "")
    .trim()
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-");
}
function uniq(arr) {
  const seen = new Set(); const out = [];
  for (const v of arr || []) { const k = typeof v === "string" ? v : JSON.stringify(v);
    if (!seen.has(k)) { seen.add(k); out.push(v); } }
  return out;
}
function truncate(s, max = 1800) {
  const str = String(s || ""); return str.length > max ? str.slice(0, max - 1) + "…" : str;
}
function sentencesToString(arr, sep = "\n") {
  const a = normalizeArray(arr).map(x => String(x).trim()); return a.join(sep).trim();
}
function buildMarkdown(article) {
  const lines = [];
  lines.push(`# ${article.title || "Untitled"}`);
  if (article.url) lines.push(article.url);
  if (article.published) lines.push(`Published: ${article.published}`);
  if (article.source) lines.push(`Source: ${article.source}`);
  if (article.author) lines.push(`Author: ${article.author}`);
  lines.push("");
  if (article.summary?.length) { lines.push("## Summary", ...article.summary, ""); }
  if (article.insights?.length) { lines.push("## SV insights", ...article.insights, ""); }
  if (article.categories?.length) lines.push(`**Categories:** ${article.categories.join(", ")}`);
  if (article.tags?.length) lines.push(`**Tags:** ${article.tags.join(", ")}`);
  if (article.refs?.length) { lines.push("", "## Refs", ...article.refs.map(r => `- ${r}`)); }
  return lines.join("\n");
}

// --- JSON hygiene ---
function stripCodeFences(s = "") {
  return String(s)
    .replace(/^\s*```(?:json)?\s*/i, "")
    .replace(/\s*```\s*$/i, "")
    .trim();
}
function sanitizeJsonish(str) {
  let t = String(str ?? "");
  t = t.replace(/^\uFEFF/, ""); // BOM
  t = t.replace(/[\u201C\u201D]/g, '"').replace(/[\u2018\u2019]/g, "'"); // quotes
  t = t.replace(/\/\*[\s\S]*?\*\//g, "");         // /* */ comments
  t = t.replace(/(^|[^:])\/\/.*$/gm, "$1");       // // comments
  for (let i = 0; i < 3; i++) t = t.replace(/,\s*(?=[}\]])/g, ""); // trailing commas
  t = t.replace(
    /([{\s,])([A-Za-z_][A-Za-z0-9_\-]*)(\s*):/g,
    (_m, p1, key, p3) => `${p1}"${key}"${p3}:`
  ); // bare keys
  t = t.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, " "); // control chars
  return t;
}

// --- Try common Gemini shapes ---
function getGeminiText(root) {
  // 1) Array root → [ { candidates: ... } ]
  if (Array.isArray(root)) {
    for (const node of root) {
      const t = getGeminiText(node);
      if (t) return t;
    }
  }
  // 2) Object with candidates[].content.parts[].text
  const parts = root?.candidates?.[0]?.content?.parts
    || root?.[0]?.candidates?.[0]?.content?.parts; // handle one more nesting
  if (Array.isArray(parts) && parts.length) {
    const joined = parts.map(p => p?.text || "").filter(Boolean).join("\n").trim();
    if (joined) return joined;
  }
  // 3) Common wrappers like .output / .text
  const textLike = root?.output ?? root?.text ?? root?.response ?? root?.content ?? root?.data;
  if (typeof textLike === "string" && textLike.trim()) return textLike.trim();
  return null;
}

// --- Deep scan for any JSON-looking string that contains "articles": ---
function* walk(o, path = []) {
  if (o && typeof o === "object") {
    if (Array.isArray(o)) {
      for (let i = 0; i < o.length; i++) yield* walk(o[i], path.concat([`[${i}]`]));
    } else {
      for (const k of Object.keys(o)) yield* walk(o[k], path.concat([`.${k}`]));
    }
  } else {
    yield { path: path.join(""), value: o };
  }
}
function findArticleJsonStrings(root) {
  const hits = [];
  for (const leaf of walk(root)) {
    if (typeof leaf.value === "string") {
      const s = leaf.value;
      if (s.includes('"articles"') && (s.includes("{") || s.includes("["))) {
        hits.push({ path: leaf.path || "(root)", text: s });
      }
    }
  }
  return hits;
}

// --- Main ---
const root = items?.[0]?.json ?? items?.[0] ?? {};

let text = getGeminiText(root);
let parsed;

// Try direct parse for the extracted text
if (text) {
  try { parsed = JSON.parse(stripCodeFences(text)); }
  catch {
    try { parsed = JSON.parse(sanitizeJsonish(stripCodeFences(text))); } catch {}
  }
}

// If still not parsed, try deep scan for any string that looks like the JSON blob
if (!parsed || !Array.isArray(parsed?.articles)) {
  const candidates = findArticleJsonStrings(root);
  for (const hit of candidates) {
    try {
      parsed = JSON.parse(stripCodeFences(hit.text));
      if (Array.isArray(parsed?.articles)) break;
    } catch {
      try {
        parsed = JSON.parse(sanitizeJsonish(stripCodeFences(hit.text)));
        if (Array.isArray(parsed?.articles)) break;
      } catch {}
    }
  }
}

// Give a helpful error with a peek at what exists
if (!parsed || !Array.isArray(parsed?.articles)) {
  const debug = {
    found_text_length: text ? text.length : 0,
    found_article_string_candidates: (findArticleJsonStrings(root).map(h => h.path)).slice(0, 5),
    top_keys_root_obj: root && typeof root === "object" && !Array.isArray(root) ? Object.keys(root).slice(0, 10) : [],
    is_root_array: Array.isArray(root),
  };
  return [{ json: { error: "No articles array found", debug } }];
}

const inArticles = parsed.articles;

// ---- Normalize & emit ----
const out = inArticles.map(a => {
  const uid = a.uid || "";
  let url = a.url || uid || "";
  try {
    if (uid && url) {
      const u1 = new URL(uid);
      const u2 = new URL(url);
      if (u1.origin + u1.pathname !== u2.origin + u2.pathname) url = uid;
    }
  } catch { if (uid) url = uid; }

  const categories = normalizeArray(a.categories);
  const refs = normalizeArray(a.refs);
  const summary = normalizeArray(a.summary);
  const insights = normalizeArray(a.insights);

  const tagsArr = uniq([
    ...normalizeArray(a.tags).map(lcHyphenateTag),
    ...categories.map(lcHyphenateTag),
  ]).filter(Boolean);

  const summary_text  = truncate(sentencesToString(summary, "\n"), 1800);
  const insights_text = truncate(sentencesToString(insights, "\n"), 1200);
  const tags_text     = truncate(tagsArr.join(", "), 400);

  const notion_content = truncate(buildMarkdown({
    title: a.title,
    url,
    published: a.published || "",
    source: a.source || "",
    author: a.author || "",
    categories,
    tags: tagsArr,
    summary,
    insights,
    refs,
  }), 1800);

  return {
    json: {
      notion_title: a.title || "",
      notion_url: url,
      notion_uid: uid,

      summary,
      insights,
      tags: tagsArr,
      categories,
      refs,

      summary_text,
      insights_text,
      tags_text,
      notion_content,

      notion_published: a.published || "",
      notion_source: a.source || "",
      notion_author: a.author || "",
    },
  };
});

return out;
